107	void spin_handler::create_matrix(
108	    const std::string &pauli_word,
109	    const std::function<void(std::size_t, std::size_t, std::complex<double>)>
110	        &process_element,
111	    bool invert_order) {
112	  auto map_state = [](char pauli, bool state) {
113	    if (state) {
114	      if (pauli == 'Z')
115	        return std::make_pair(std::complex<double>(-1., 0.), bool(state));
116	      if (pauli == 'X')
117	        return std::make_pair(std::complex<double>(1., 0.), !state);
118	      if (pauli == 'Y')
119	        return std::make_pair(std::complex<double>(0., -1.), !state);
120	      return std::make_pair(std::complex<double>(1., 0.), bool(state));
121	    } else {
122	      if (pauli == 'Z')
123	        return std::make_pair(std::complex<double>(1., 0.), bool(state));
124	      if (pauli == 'X')
125	        return std::make_pair(std::complex<double>(1., 0.), !state);
126	      if (pauli == 'Y')
127	        return std::make_pair(std::complex<double>(0., 1.), !state);
128	      return std::make_pair(std::complex<double>(1., 0.), bool(state));
129	    }
130	  };
131	
132	  auto dim = 1ul << pauli_word.size();
133	  auto nr_deg = pauli_word.size();
134	
135	  for (std::size_t old_state = 0; old_state < dim; ++old_state) {
136	    std::size_t new_state = 0;
137	    std::complex<double> entry = 1.;
138	    for (std::size_t degree = 0; degree < nr_deg; ++degree) {
139	      auto state = (old_state & (1ul << degree)) >> degree;
140	      auto op = pauli_word[invert_order ? nr_deg - 1 - degree : degree];
141	      auto mapped = map_state(op, state);
142	      entry *= mapped.first;
143	      new_state |= (mapped.second << degree);
144	    }
145	    process_element(new_state, old_state, entry);
146	  }
