292	// Generally speaking, degrees of freedom can (and should) be grouped
293	// into particles/states of different kind. For example, a system may
294	// consist of both boson and fermion particles. Regardless of how an
295	// operator is composed, the particle kind of each degree should always
296	// remain fixed. Since "degrees" are runtime information, we approximate
297	// the distinction of particles via distinguishing operator types. This
298	// distinction at the type system level is only possible when we have
299	// a single kind of particle in an operator. As soon as we have different
300	// kinds, the operators get converted to a general "matrix operator" type,
301	// and we rely on runtime tracking to enforce the correct particle-kind
302	// specific behavior for subsequent manipulations of the operator.
303	// The commutation relations declared below store the information about
304	// what kind of particles an operator acts on. Each "kind" of particles
305	// is assigned a unique id, as well as a complex value that reflects the
306	// factor acquired when two operator that act on the same group of particles
307	// are exchanged (e.g. 1 for bosons, and -1 for fermions).
308	struct commutation_relations {
309	  friend class operator_handler;
310	
311	private:
312	  // The factor that should be applied when exchanging two operators with the
313	  // same group id that act on different degrees of freedom. E.g. for fermion
314	  // relations {a†(k), a(q)} = 0 for k != q, the exchange factor is -1.
315	  static std::unordered_map<uint, std::complex<double>> exchange_factors;
316	
317	  // The id for the "commutation set" an operator class or instance belongs to.
318	  // If the id is negative, it indicates that operators of this kind
319	  // always commute with all other operators.
320	  int id;
321	
322	  constexpr commutation_relations(int group_id) : id(group_id) {}
323	
324	public:
325	  // Negative ids are reserved for the operator classes that CUDA-Q defines.
326	  void define(uint group_id, std::complex<double> exchange_factor);
327	
328	  constexpr commutation_relations(const commutation_relations &other)
329	      : id(other.id) {}
330	
331	  constexpr commutation_relations &
332	  operator=(const commutation_relations &other) {
333	    if (this != &other) {
334	      this->id = other.id;
335	    }
336	    return *this;
337	  }
338	
339	  std::complex<double> commutation_factor() const;
340	
341	  bool operator==(const commutation_relations &other) const;
342	};
