475	  to_matrix(std::unordered_map<std::size_t, std::int64_t> &dimensions,
476	            const std::unordered_map<std::string, std::complex<double>>
477	                &parameters = {}) const = 0;
478	
479	  /// @brief Converts the object to a string representation.
480	  /// @param include_degrees A boolean flag indicating whether to include
481	  /// degrees in the string representation.
482	  /// @return A string representation of the object.
483	  virtual std::string to_string(bool include_degrees = true) const = 0;
484	};
485	
486	// An adapter for operator handler classes that can generate multi-diagonal
487	// representation.
