147	  auto it = matrix_handler::defined_ops.find(this->op_code);
148	  assert(it != matrix_handler::defined_ops
149	                   .end()); // should be validated upon instantiation
150	
151	  for (auto i = 0; i < this->targets.size(); ++i) {
152	    auto entry = dimensions.find(this->targets[i]);
153	    auto expected_dim = it->second.expected_dimensions[i];
154	    if (expected_dim <= 0) {
155	      if (entry == dimensions.end())
156	        throw std::runtime_error("missing dimension for degree " +
157	                                 std::to_string(this->targets[i]));
158	      relevant_dims.push_back(entry->second);
159	    } else {
160	      if (entry == dimensions.end())
161	        dimensions[this->targets[i]] = expected_dim;
162	      else if (entry->second != expected_dim)
163	        throw std::runtime_error(
164	            "invalid dimension for degree " + std::to_string(this->targets[i]) +
165	            ", expected dimension is " + std::to_string(expected_dim));
166	      relevant_dims.push_back(expected_dim);
167	    }
168	  }
169	  return this->op_code;
170	}
