212	matrix_handler::matrix_handler(std::string operator_id,
213	                               const std::vector<std::size_t> &degrees,
214	                               const commutation_behavior &commutation_behavior)
215	    : op_code(operator_id),
216	      commutes(commutation_behavior.commutes_across_degrees),
217	      group(commutation_behavior.group), targets(degrees) {
218	  if (!commutation_behavior.commutes_across_degrees && this->targets.size() > 1)
219	    // We cannot support this with the current mechanism for achieving
220	    // non-trivial commutation relations for operators acting on different
221	    // degrees. See also the comment in the `find_insert_at` template for
222	    // product operators. We still want to stick with that mechanism, since it
223	    // is more general and by far more performant than e.g. achieving
224	    // anti-commutation via phase operator instead. It should be fine, however,
225	    // for a multi-qubit operator to belong to a non-zero commutation set as
226	    // long as the operator itself commutes with all operators acting on
227	    // different degrees (as indicated by the boolean value of
228	    // commutation_behavior); this effectively "marks" the degrees that the
229	    // operator acts on as being a certain kind of particles.
230	    throw std::runtime_error("non-trivial commutation behavior is not "
231	                             "supported for multi-target operators");
232	}
