239	      group(commutation_behavior.group), targets(std::move(degrees)) {
240	  if (!commutation_behavior.commutes_across_degrees && this->targets.size() > 1)
241	    // We cannot support this with the current mechanism for achieving
242	    // non-trivial commutation relations for operators acting on different
243	    // degrees. See also the comment in the `find_insert_at` template for
244	    // product operators. We still want to stick with that mechanism, since it
245	    // is more general and by far more performant than e.g. achieving
246	    // anti-commutation via phase operator instead. It should be fine, however,
247	    // for a multi-qubit operator to belong to a non-zero commutation set as
248	    // long as the operator itself commutes with all operators acting on
249	    // different degrees (as indicated by the boolean value of
250	    // commutation_behavior); this effectively "marks" the degrees that the
251	    // operator acts on as being a certain kind of particles.
252	    throw std::runtime_error("non-trivial commutation behavior is not "
253	                             "supported for multi-target operators");
