263	template <typename T,
264	          std::enable_if_t<std::is_base_of_v<operator_handler, T>, bool>>
265	matrix_handler::matrix_handler(const T &other,
266	                               const commutation_behavior &behavior)
267	    : op_code(matrix_handler::type_prefix<T>() + other.to_string(false)),
268	      commutes(behavior.commutes_across_degrees), group(behavior.group),
269	      targets(other.degrees()) {
270	  if (matrix_handler::defined_ops.find(this->op_code) ==
271	      matrix_handler::defined_ops.end()) {
272	    auto func = [other](const std::vector<std::int64_t> &dimensions,
273	                        const std::unordered_map<std::string,
274	                                                 std::complex<double>> &_none) {
275	      std::unordered_map<std::size_t, std::int64_t> dims;
276	      auto targets = other.degrees();
277	      for (auto i = 0; i < dimensions.size(); ++i)
278	        dims[targets[i]] = dimensions[i];
279	      return other.to_matrix(dims, _none);
280	    };
281	    // the to_matrix method on the spin op will check the dimensions, so we
282	    // allow arbitrary here
283	    std::vector<std::int64_t> required_dimensions(this->targets.size(), -1);
284	
285	    if constexpr (std::is_base_of_v<mdiag_operator_handler, T>) {
286	      auto dia_func =
287	          [other](const std::vector<std::int64_t> &dimensions,
288	                  const std::unordered_map<std::string, std::complex<double>>
289	                      &_none) {
290	            std::unordered_map<std::size_t, std::int64_t> dims;
291	            auto targets = other.degrees();
292	            for (auto i = 0; i < dimensions.size(); ++i)
293	              dims[targets[i]] = dimensions[i];
294	            return other.to_diagonal_matrix(dims, _none);
295	          };
296	      matrix_handler::define(this->op_code, std::move(required_dimensions),
297	                             func, std::move(dia_func));
298	    } else {
299	      matrix_handler::define(this->op_code, std::move(required_dimensions),
300	                             func);
301	    }
302	  }
303	}
