470	    auto func =
471	        [](const std::vector<std::int64_t> &dimensions,
472	           const std::unordered_map<std::string, std::complex<double>> &_none) {
473	          std::size_t dimension = dimensions[0];
474	          auto mat = complex_matrix(dimension, dimension);
475	          for (std::size_t i = 0; i < dimension; i++) {
476	            mat[{i, i}] = i & 1 ? -1. : 1.;
