485	matrix_handler matrix_handler::position(std::size_t degree) {
486	  std::string op_code = "position";
487	  if (matrix_handler::defined_ops.find(op_code) ==
488	      matrix_handler::defined_ops.end()) {
489	    auto func =
490	        [](const std::vector<std::int64_t> &dimensions,
491	           const std::unordered_map<std::string, std::complex<double>> &_none) {
492	          std::size_t dimension = dimensions[0];
493	          auto mat = complex_matrix(dimension, dimension);
494	          // position = 0.5 * (create + annihilate)
495	          for (std::size_t i = 0; i + 1 < dimension; i++) {
496	            mat[{i + 1, i}] = 0.5 * std::sqrt(static_cast<double>(i + 1));
497	            mat[{i, i + 1}] = 0.5 * std::sqrt(static_cast<double>(i + 1));
498	          }
499	          return mat;
500	        };
501	    matrix_handler::define(op_code, {-1}, func);
502	  }
503	  return matrix_handler(op_code, {degree});
504	}
