506	matrix_handler matrix_handler::momentum(std::size_t degree) {
507	  std::string op_code = "momentum";
508	  if (matrix_handler::defined_ops.find(op_code) ==
509	      matrix_handler::defined_ops.end()) {
510	    auto func =
511	        [](const std::vector<std::int64_t> &dimensions,
512	           const std::unordered_map<std::string, std::complex<double>> &_none) {
513	          std::size_t dimension = dimensions[0];
514	          auto mat = complex_matrix(dimension, dimension);
515	          // momentum = 0.5j * (create - annihilate)
516	          for (std::size_t i = 0; i + 1 < dimension; i++) {
517	            mat[{i + 1, i}] = std::complex<double>(0., 0.5) *
518	                              std::sqrt(static_cast<double>(i + 1));
519	            mat[{i, i + 1}] = std::complex<double>(0., -0.5) *
520	                              std::sqrt(static_cast<double>(i + 1));
521	          }
522	          return mat;
523	        };
524	    matrix_handler::define(op_code, {-1}, func);
525	  }
526	  return matrix_handler(op_code, {degree});
527	}
