529	matrix_handler matrix_handler::displace(std::size_t degree) {
530	  std::string op_code = "displace";
531	  if (matrix_handler::defined_ops.find(op_code) ==
532	      matrix_handler::defined_ops.end()) {
533	    auto func = [](const std::vector<std::int64_t> &dimensions,
534	                   const std::unordered_map<std::string, std::complex<double>>
535	                       &parameters) {
536	      std::size_t dimension = dimensions[0];
537	      auto entry = parameters.find("displacement");
538	      if (entry == parameters.end())
539	        throw std::runtime_error("missing value for parameter 'displacement'");
540	      auto displacement_amplitude = entry->second;
541	      auto create = complex_matrix(dimension, dimension);
542	      auto annihilate = complex_matrix(dimension, dimension);
543	      for (std::size_t i = 0; i + 1 < dimension; i++) {
544	        create[{i + 1, i}] = std::sqrt(static_cast<double>(i + 1));
545	        annihilate[{i, i + 1}] = std::sqrt(static_cast<double>(i + 1));
546	      }
547	      auto term1 = displacement_amplitude * create;
548	      auto term2 = std::conj(displacement_amplitude) * annihilate;
549	      return (term1 - term2).exponential();
550	    };
551	    matrix_handler::define(
552	        op_code, {-1}, func,
553	        {{"displacement",
554	          "Amplitude of the displacement operator. See also "
555	          "https://en.wikipedia.org/wiki/Displacement_operator."}});
556	  }
557	  return matrix_handler(op_code, {degree});
558	}
559	
560	matrix_handler matrix_handler::squeeze(std::size_t degree) {
561	  std::string op_code = "squeeze";
562	  if (matrix_handler::defined_ops.find(op_code) ==
563	      matrix_handler::defined_ops.end()) {
564	    auto func = [](const std::vector<std::int64_t> &dimensions,
565	                   const std::unordered_map<std::string, std::complex<double>>
566	                       &parameters) {
567	      std::size_t dimension = dimensions[0];
568	      auto entry = parameters.find("squeezing");
569	      if (entry == parameters.end())
570	        throw std::runtime_error("missing value for parameter 'squeezing'");
571	      auto squeezing = entry->second;
572	      auto create = complex_matrix(dimension, dimension);
573	      auto annihilate = complex_matrix(dimension, dimension);
574	      for (std::size_t i = 0; i + 1 < dimension; i++) {
575	        create[{i + 1, i}] = std::sqrt(static_cast<double>(i + 1));
576	        annihilate[{i, i + 1}] = std::sqrt(static_cast<double>(i + 1));
577	      }
578	      auto term1 = std::conj(squeezing) * annihilate.power(2);
579	      auto term2 = squeezing * create.power(2);
580	      auto difference = 0.5 * (term1 - term2);
581	      return difference.exponential();
582	    };
583	    matrix_handler::define(
584	        op_code, {-1}, func,
585	        {{"squeezing", "Amplitude of the squeezing operator. See also "
586	                       "https://en.wikipedia.org/wiki/Squeeze_operator."}});
587	  }
588	  return matrix_handler(op_code, {degree});
589	}
